import{_ as n,o as r,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F01: 營收因子與定價權分析","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F01_營收因子與定價權分析_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F01_營收因子與定價權分析_財務分析專家.md"}'),l={name:"32Ｑ題本＿重要/財務組/F01_營收因子與定價權分析_財務分析專家.md"};function t(a,o,s,g,c,d){return r(),e("div",null,[...o[0]||(o[0]=[i('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f01-營收因子與定價權分析" tabindex="-1">F01: 營收因子與定價權分析 <a class="header-anchor" href="#f01-營收因子與定價權分析" aria-label="Permalink to &quot;F01: 營收因子與定價權分析&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F01</li><li><strong>題目：</strong> 營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)」？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 具備 12 年以上 FP&amp;A 與三表聯動建模經驗，善於執行「營收橋接 (Revenue Bridge)」分析。能精準拆解價格彈性與銷量動能，判定公司業績是來自「品牌溢價」還是「低價紅海」，為未來毛利預測提供核心基準。</li><li><strong>意圖：</strong> 執行「營收成長含金量審計」——透過拆解 P (價格) 與 V (銷量)，判定公司業績成長的真實驅動力。識別該公司是具備「轉嫁成本能力」的領先者（漲價型成長），還是陷入「削價競爭」的紅海追隨者（衝量型成長），以此判斷未來利潤率的可持續性與投資價值的含金量。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心動能底座：FinMind】</strong>：調用 <code>TaiwanStockRevenue</code>。作為審計的第一步，核實近一年度營收之月增/年增趨勢，定位「異動發生的關鍵月份」。</li><li><strong>【深度拆解實體：Annual Report (年報)】</strong>：進入 <code>業務概況 -&gt; 主要產品之銷售量值表</code>。在確認營收異動後，提取「每單位平均售價 (ASP)」與「實體銷售總量 (Volume)」，執行營收橋接分析。</li><li><strong>【獲利指引：法說會簡報 (Investor Presentation)】</strong>：檢索公司對「ASP 走勢 (Average Selling Price Trend)」的官方口徑與未來調價展望。</li><li><strong>【外部市場連動：Web Search】</strong>：搜尋漲價函、產品缺貨新聞或同業行情。用於核實公司定價權是否優於產業。</li></ol></li><li><strong>邏輯：</strong> 執行「營收橋接 (Revenue Bridge) 壓力測試」——模擬若單價下滑 5% 或銷量萎縮 10% 對營益率的衝擊程度；「毛利聯測」——若單價上升但毛利率持平或下滑，判定為「成本推升型漲價」而非「獲利擴張型漲價」。</li><li><strong>來源：</strong> <code>FinMind (營收動能)</code>, <code>年報 (銷售量值表)</code>, <code>法說會 PPT (ASP 指引)</code>, <code>產業報價網站 (如 TrendForce/DRAMeXchange)</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py revenue_bridge [股號]</code> → 取得年度營收、YOY 成長、月營收細節</li><li><strong>跑工具</strong>：<code>python3 財務分析工具.py margin_analysis [股號]</code> → 取得毛利率/營益率/淨利率趨勢</li><li><strong>判讀驅動因子</strong>：對比營收成長率與毛利率趨勢——營收成長但毛利率下滑 → 衝量型（Volume Up）；營收成長且毛利率穩定或提升 → 定價型（Price Up）</li><li><strong>年報補充</strong>：若工具數據不足（如 ASP 明細），用 <code>pdf</code> 工具指定頁碼提取「主要產品之銷售量值表」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【P/V 貢獻拆解】</strong>：智慧體<strong>必須</strong>執行自最新年度 $Y$ 溯回至 $Y-3$ 之四年度財務對比分析，並計算「價格貢獻額」與「銷量貢獻額」。嚴禁模糊描述「價量齊揚」，必須給出哪個因子是主驅動力。</li><li><strong>【定價權穿透】</strong>：搜尋是否有「領先調價」之新聞。若公司能領先同業漲價且不失市佔，判定具備強大「護城河」；若漲價後銷量暴跌，標註為「定價權衰退」。</li><li><strong>【庫存去化連動】</strong>：對照 F06/F07 的存貨數據。若營收成長來自衝銷量 (Volume Up) 但存貨天數拉長，必須質疑是否為「通路塞貨」或「降價清庫存」。</li><li><strong>【毛利背離警告】</strong>：若 ASP 增加但毛利下降，必須發出「供應鏈成本失控」或「轉嫁能力虛弱」之警告。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：嚴禁使用「表現不俗」、「營收亮眼」。必須量化為「ASP 變動率 %」與「實體銷量 YOY %」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f01-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F01 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f01-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F01 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「動態橋接+獲利韌性」結構（例：該公司營收成長主要由 [單價 P] 驅動，顯示具備強大 [定價權]，足以覆蓋 [成本上升]；[銷量 V] 雖微幅下滑，但轉向 [高毛利組合] 有利未來業績）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：價量齊揚（漲價同時銷量成長），展現極高的市場統治力與產品競爭力。</li><li><strong>A (良)</strong>：單價穩定，成長主要由銷量帶動（市佔率擴張）；或單價成功轉嫁成本而銷量持平。</li><li><strong>B (持平)</strong>：靠降價衝量（Price Down, Volume Up），或單價雖漲但銷量劇減，顯示競爭優勢正在流失。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：依照以下三個維度回答： <ol><li><strong>驅動因子權重 (Driver Weight)</strong>：價格變動與銷量變動對總營收變動的具體比例。</li><li><strong>獲利品質連動 (Margin Linkage)</strong>：漲價/衝量行為對毛利率的實質貢獻。</li><li><strong>未來路徑預測 (Future Path)</strong>：當前的 P/V 組合是否能支撐接下來 2-3 季的業績成長。</li></ol></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出年報頁碼、法說會簡報提及之數據或市場報價趨勢。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：分析「量 (Volume)」與「價 (Price)」的連動關係。專家應在此處診斷當前的毛利擴張是來自「成本下降」還是「定價權提升」，並給出關於企業競爭力可持續性的判斷。需警惕「以量補價」後的毛利斷崖。判定公司目前是處於「品牌溢價紅利期」還是「價格戰苦鬥期」，並點出這對未來股票價值重估的實質影響。</li></ul>',11)])])}const h=n(l,[["render",t]]);export{u as __pageData,h as default};
